# Get the key dimensions of the enclosure and wedge shelf construction planes
result_data = {}

# Enclosure bounding box
for body in rootComp.bRepBodies:
    if body.name == "Enclosure_Shell":
        bb = body.boundingBox
        result_data['enclosure'] = {
            'min': [bb.minPoint.x, bb.minPoint.y, bb.minPoint.z],
            'max': [bb.maxPoint.x, bb.maxPoint.y, bb.maxPoint.z]
        }

# Check the shelf construction planes
shelf_planes = {}
for cp in rootComp.constructionPlanes:
    if 'Shelf' in cp.name or 'Lid' in cp.name:
        # Get offset value if possible
        shelf_planes[cp.name] = str(cp.geometry)

result_data['shelf_planes'] = list(shelf_planes.keys())

# Check timeline items 117-166 status summary
timeline = design.timeline
wedge_items = []
for i in range(117, min(167, timeline.count)):
    item = timeline.item(i)
    wedge_items.append({
        'index': i,
        'name': item.entity.name if hasattr(item.entity, 'name') else str(i),
        'suppressed': item.isSuppressed
    })

result_data['wedge_timeline'] = wedge_items
result = result_data
